'use client'
// app/auth/page.tsx
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase'

const LOGO_SRC = "data:image/png;base64,"

export default function AuthPage() {
  const router = useRouter()
  const supabase = createClient()
  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)
  const [showPwd, setShowPwd] = useState(false)

  async function handleLogin(e: React.FormEvent) {
    e.preventDefault()
    setError(''); setLoading(true)
    const email = `${username.trim().toLowerCase()}@mrdiy.internal`
    const { error: err } = await supabase.auth.signInWithPassword({ email, password })
    if (err) { setError('Invalid username or password.'); setLoading(false); return }
    router.push('/dashboard')
    router.refresh()
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center relative" style={{background:'#1A1A1A'}}>

      {/* Login card */}
      <div className="bg-white rounded-2xl shadow-2xl text-center" style={{padding:'40px 44px', width:'400px', maxWidth:'95vw'}}>
        {/* Logo */}
        <div className="flex items-center justify-center mb-2">
          <img src={LOGO_SRC} alt="MR DIY" style={{width:'90px', height:'90px', objectFit:'contain'}} />
        </div>
        <p className="font-extrabold tracking-widest uppercase mb-8" style={{fontSize:'11px', letterSpacing:'3px', color:'#888880'}}>MR DIY Campaign Job Tracker</p>

        {error && (
          <div className="mb-4 px-4 py-3 rounded-lg text-sm font-bold" style={{background:'#FFF1F1', border:'1px solid #FFBBBB', color:'#C92B2B'}}>
            {error}
          </div>
        )}

        <form onSubmit={handleLogin}>
          <label className="block text-left font-extrabold tracking-widest uppercase mb-1" style={{fontSize:'10px', color:'#888880'}}>Username</label>
          <input
            className="w-full mb-4 px-4 py-3 rounded-lg outline-none transition-all"
            style={{background:'#F7F6F2', border:'1.5px solid #E2DFD3', fontFamily:'"Barlow Condensed",sans-serif', fontSize:'15px'}}
            placeholder="Enter username"
            value={username} onChange={e => setUsername(e.target.value)}
            autoComplete="username" required
          />
          <label className="block text-left font-extrabold tracking-widest uppercase mb-1" style={{fontSize:'10px', color:'#888880'}}>Password</label>
          <div className="relative mb-5">
            <input
              type={showPwd ? 'text' : 'password'}
              className="w-full px-4 py-3 rounded-lg outline-none transition-all"
              style={{background:'#F7F6F2', border:'1.5px solid #E2DFD3', fontFamily:'"Barlow Condensed",sans-serif', fontSize:'15px', paddingRight:'44px'}}
              placeholder="Enter password"
              value={password} onChange={e => setPassword(e.target.value)}
              autoComplete="current-password" required
            />
            <button type="button" onClick={() => setShowPwd(p => !p)}
              style={{position:'absolute', right:'12px', top:'50%', transform:'translateY(-50%)', background:'none', border:'none', cursor:'pointer', fontSize:'18px', color:'#888880', padding:'2px 4px', lineHeight:1}}>
              {showPwd ? '🙈' : '👁️'}
            </button>
          </div>
          <button
            type="submit"
            disabled={loading}
            className="w-full py-3 rounded-xl font-extrabold tracking-wide uppercase text-base transition-all"
            style={{background:'#FFD600', color:'#1A1A1A', fontFamily:'"Barlow Condensed",sans-serif', opacity:loading?0.7:1}}
          >
            {loading ? 'Signing in…' : 'Sign In →'}
          </button>
        </form>
      </div>

      {/* Disclaimer */}
      <div className="absolute bottom-5 left-0 right-0 text-center px-5" style={{fontFamily:'"Barlow Condensed",sans-serif', fontSize:'10px', fontWeight:600, letterSpacing:'.5px', color:'rgba(255,255,255,.25)', lineHeight:'1.6'}}>
        This system is the proprietary technology of C&amp;C Creative Consultancy Sdn Bhd.<br />
        Unauthorized use or reproduction is prohibited.
      </div>

    </div>
  )
}
